{
  "病情摘要": "患者为72岁男性，COPD病史6年，已戒烟1年。近期咳嗽略增伴白痰，无发热，活动后气促稳定（mMRC 2级），静息SpO2 95%。关键异常为吸入制剂使用频次不规律且操作手法不规范（未充分呼气、未屏气、未漱口），存在药物疗效打折及局部真菌感染风险。整体目前处于相对稳定期，但存在可控的依从性与技术缺陷。",
  "依从性": {
    "用药": "吸入制剂使用频次不足（有时仅1次/日），且操作手法错误（未充分呼气、未屏气、未漱口）。需严格按处方规定频次规律使用，切勿自行减量或停药；必须重新培训标准吸入流程，强调用后清水漱口以防口腔念珠菌感染。",
    "饮食运动": "未提及。建议均衡营养，保证优质蛋白与充足水分摄入以稀释痰液；避免过饱影响膈肌运动；在耐受范围内开展适度有氧活动，避免剧烈运动与过度疲劳。",
    "复诊检查": "未提及。建议遵医嘱定期复查肺功能、动脉血气或胸部影像，按时参加呼吸专科随访，勿延误常规评估。"
  },
  "居家监测": {
    "项目": [
      "症状变化（咳嗽频率、咳痰量及性状、气促程度）",
      "指脉氧饱和度（SpO2）",
      "体温"
    ],
    "频率": "每日至少1-2次，症状波动或环境变化时随时监测",
    "目标": "静息SpO2维持≥90%（或遵医嘱个体化目标），痰液保持清稀或白色，气促mMRC分级不升级，体温正常",
    "记录要求": "使用专用记录本或电子表格记录日期、时间、数值及伴随症状，复诊时完整提交医护人员用于疗效评估与方案调整"
  },
  "风险分层": {
    "级别": "中风险",
    "依据": [
      "近一周咳嗽略增多伴白痰，提示气道炎症可能轻度活动",
      "吸入装置使用频次不足且操作手法不规范，显著影响药物沉积与临床疗效",
      "静息SpO2 95%，无发热及急性加重典型表现，目前生命体征平稳"
    ]
  },
  "随访建议": {
    "方式": "视频/电话随访结合门诊实地指导",
    "时间": "1周后电话随访评估症状演变；建议1个月内至呼吸科门诊复诊，现场纠正吸入技术并评估肺功能",
    "护理措施": [
      "重新演示标准吸入流程（充分呼气→密封含嘴→匀速深吸气→屏气10秒→缓慢呼气→清水漱口）并要求患者独立回示直至熟练",
      "核对当前处方频次，强调规律用药重要性，禁止自行调药",
      "指导环境管理（保持室内适宜温湿度，避免冷空气、粉尘及刺激性气体直接吸入）",
      "教授缩唇呼吸与腹式呼吸训练，每日2次，每次10-15分钟，改善通气效率"
    ]
  },
  "需就医/升级条件": [
    "痰液转为黄脓痰、黏稠难咳或带血，或咳嗽咳痰明显加重持续超3天",
    "静息或轻微活动后SpO2降至≤88%，或较平时基线下降≥4%",
    "出现发热（体温≥38℃）、胸痛、意识改变、下肢水肿或心率显著增快",
    "气促进行性加重，mMRC评分升至3级及以上，日常活动严重受限",
    "家庭氧疗期间若已吸氧但SpO2仍无法维持目标值，或出现头痛、嗜睡等二氧化碳潴留征象"
  ],
  "健康教育": [
    "掌握正确吸入装置使用方法及用后彻底漱口以预防口腔念珠菌感染和声音嘶哑",
    "识别COPD急性加重早期信号（痰量增、脓性变、气促加剧），及时干预避免进展",
    "坚持长期戒烟并远离二手烟及职业/环境污染物，降低复发风险",
    "合理膳食，保证优质蛋白与充足水分摄入，维持健康体重，避免营养不良或肥胖加重呼吸负担",
    "循序渐进开展呼吸康复训练，学会能量保存技巧，提高日常生活耐力"
  ]
}

{
  "病情摘要": "患者女，55岁，高血压病史10年，合并慢性肾病（CKD）2期伴尿微量白蛋白升高。近1个月家庭血压控制不佳（多在145-155/85-92 mmHg）。近期血肌酐稳定，无水肿及尿量异常。核心问题为血压未达标、晚间降压药漏服及午餐高盐饮食，存在加速肾脏损害及心血管事件的风险。",
  "依从性": {
    "用药": "存在晚间降压药漏服情况，导致血压日间波动。需建立固定服药流程，严禁自行加药、减药或停药。若频繁漏服，需由主治医生评估是否调整为长效制剂或优化给药时间。",
    "饮食运动": "午餐食堂口味偏咸，钠摄入超标，直接加剧水钠潴留与血压升高。未提及规律运动情况，需补充评估心肺耐力与运动禁忌。建议严格限盐，逐步增加中等强度有氧运动。",
    "复诊检查": "未提及近期复查计划。需按医嘱定期监测肾功能、尿微量白蛋白/肌酐比值（UACR）及电解质，以评估肾脏保护效果与治疗安全性。"
  },
  "居家监测": {
    "项目": [
      "家庭血压（收缩压/舒张压、心率）",
      "体重变化",
      "尿液性状（泡沫、颜色、尿量）"
    ],
    "频率": "血压每日早晚各测量1次（每次静坐5分钟后测2-3遍取平均值）；体重每周固定时间测量2-3次；尿液性状每日观察。",
    "目标": "血压目标建议控制在<130/80 mmHg（具体需结合医生评估个体化设定）；体重较基线波动不超过±2kg；尿量维持正常范围。",
    "记录要求": "使用纸质记录本或健康管理APP详细记录测量日期、时间、数值及当时状态（如服药后、活动前）。复诊时务必携带完整记录供医护人员分析血压节律与疗效。"
  },
  "风险分层": {
    "级别": "中高风险",
    "依据": [
      "血压持续高于CKD合并高血压推荐目标值",
      "已存在靶器官损害证据（CKD 2期伴尿微量白蛋白升高）",
      "服药依从性差且饮食结构不合理，疾病进展风险显著增加"
    ]
  },
  "随访建议": {
    "方式": "电话随访结合门诊复诊",
    "时间": "2周后进行电话随访核实血压控制与用药依从性；1个月内安排门诊复诊，评估肾功能指标并调整治疗方案。",
    "护理措施": [
      "协助制定防漏服策略（如使用七格分装药盒、设置手机重复闹钟、将药盒置于固定显眼处）",
      "指导低盐饮食实操技巧（使用定量限盐勺，每日食盐<5g；减少酱油、咸菜、加工肉类摄入；多利用葱姜蒜、醋、柠檬汁调味）",
      "强化医患沟通，明确血压达标对逆转微量白蛋白尿及延缓肾病进展的关键作用，提升自我管理动机"
    ]
  },
  "需就医/升级条件": [
    "家庭血压持续≥160/100 mmHg，或伴剧烈头痛、眩晕、胸闷、胸痛、视物模糊",
    "出现双下肢凹陷性水肿、尿量显著减少（<400ml/日）或夜尿次数明显增多",
    "尿液呈洗肉水色或泡沫突然大量增加且不消散",
    "出现严重乏力、恶心呕吐、肌肉无力或心悸（警惕高钾血症或肾功能急性恶化）",
    "发生跌倒、意识改变或疑似感染发热"
  ],
  "健康教育": [
    "高血压与慢性肾病互为因果，严格控制血压是保护残余肾功能、降低心血管风险的首要措施",
    "严格执行低盐饮食，注意识别食品标签中的‘隐形盐’（如味精、鸡精、挂面、罐头），养成阅读营养标签的习惯",
    "建立自动化服药提醒系统，切勿因工作忙碌自行中断或更改降压方案",
    "在血压平稳前提下，每周进行至少150分钟中等强度有氧运动（如快走、慢跑、游泳），运动前后监测血压",
    "微量白蛋白尿处于可逆阶段，通过规范控压、限盐及必要时联合RAS抑制剂治疗，多数患者可实现蛋白尿转阴或显著下降"
  ]
}

{
  "病情摘要": "患者为12年糖尿病史女性，目前空腹血糖控制欠佳（7.8-9.0 mmol/L）。主要异常为双足麻木症状进行性加重，提示糖尿病周围神经病变可能进展；左足小趾外侧存在0.5 cm摩擦性水疱伴轻度红斑，属糖尿病足高危皮损。家属已采取试水温措施，居家安全意识较好。无发热等全身感染征象。",
  "依从性": {
    "用药": "未提及具体降糖药物及剂量。建议携带当前用药清单至门诊由医生评估是否需要调整，严禁自行加药、停药或更改剂量。",
    "饮食运动": "未提及。建议维持糖尿病均衡饮食，但鉴于足部存在水疱及麻木，近期应避免长时间站立或步行，以室内活动为主，防止足部进一步受压损伤。",
    "复诊检查": "未提及近期化验情况。建议尽快完善糖化血红蛋白、肝肾功能、血脂及下肢血管超声、神经传导速度等检查，以全面评估代谢控制及并发症状态。"
  },
  "居家监测": {
    "项目": [
      "指尖血糖（空腹及餐后2小时）",
      "双足皮肤完整性（颜色、温度、水疱/溃疡/破损）、感觉及肿胀情况",
      "血压"
    ],
    "频率": "血糖：每日至少测1-2次或遵医嘱；足部检查：每日早晚各1次；血压：每周2-3次或遵医嘱。",
    "目标": "空腹血糖控制在7.0 mmol/L左右（个体化调整），餐后2小时血糖<10.0 mmol/L；足部皮肤保持完整干燥，无新增水疱/破溃，皮温对称，麻木感不进一步恶化。",
    "记录要求": "使用专用记录本或APP登记血糖数值、测量时间及对应饮食/活动情况；每日拍摄足部皮损高清照片对比变化；复诊时务必携带完整记录及照片供医护人员评估。"
  },
  "风险分层": {
    "级别": "中高风险",
    "依据": [
      "糖尿病病程长达12年，合并进行性加重的双足麻木（周围神经病变进展）",
      "左足新发水疱伴局部发红，属糖尿病足高危皮损，极易在摩擦下破溃继发感染",
      "空腹血糖持续偏高（7.8-9.0 mmol/L），提示近期代谢控制不稳定"
    ]
  },
  "随访建议": {
    "方式": "门诊复诊（内分泌科或糖尿病足/创面修复专科）结合居家护理指导",
    "时间": "建议1周内完成门诊就诊；居家监测与护理即刻开始并持续执行",
    "护理措施": [
      "立即停用新鞋，更换前掌宽大、鞋底柔软防滑的鞋子及纯棉无缝线袜",
      "严格保护水疱完整性，切勿自行挑破、挤压或涂抹碘酒/酒精等刺激性消毒剂",
      "每日用37℃以下温水洗脚，洗后彻底擦干趾缝，可薄涂凡士林保湿但避免趾间潮湿",
      "家属协助每日检查足底及趾缝，发现异常及时拍照记录",
      "保持血糖平稳，避免剧烈波动影响神经与血管修复"
    ]
  },
  "需就医/升级条件": [
    "水疱自然破溃、渗液增多、化脓或周围红肿范围扩大",
    "足部出现持续性剧痛、皮温升高、发黑坏死或散发异味",
    "伴随发热（体温≥38.0℃）、寒战、乏力等全身感染症状",
    "血糖持续＞13.9 mmol/L或频繁发生＜3.9 mmol/L的低血糖",
    "双足麻木迅速加重导致行走困难、跌倒风险增加或出现肌肉萎缩"
  ],
  "健康教育": [
    "糖尿病足“五步防护法”：每日检查、正确洗脚、适度保湿、合鞋护足、规范修剪趾甲",
    "周围神经病变患者对温度与痛觉迟钝，严禁使用热水袋、电热毯直接接触足部，洗脚必须由家人试温或使用温度计",
    "均衡营养配合适度活动有助于改善微循环，但足部有皮损期间应以休息和抬高患肢为主",
    "强调糖尿病并发症管理的长期性，即使无症状也需每年至少进行一次全面的足病专科筛查（包括10g尼龙丝试验、音叉振动觉、踝肱指数等）"
  ]
}
